import Anthropic from '@anthropic-ai/sdk';
import * as XLSX from 'xlsx';

export const config = {
  api: { bodyParser: { sizeLimit: '10mb' } }
};

const TEMPLATE_B64 = ``;

const SECTIONS = {
  "교회체크카드": {
    "심방사역비": [5, 9],
    "마을사역비": [21, 25],
    "기타": [37, 42],
  },
  "개인카드": {
    "심방사역비": [6, 10],
    "마을사역비": [22, 27],
    "기타": [38, 55],
  },
};

function dateToExcelSerial(dateStr) {
  const parts = dateStr.split('/').map(Number);
  const d = new Date(parts[0], parts[1] - 1, parts[2]);
  const epoch = new Date(1899, 11, 30);
  return Math.floor((d - epoch) / 86400000);
}

export default async function handler(req, res) {
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });

  const { action } = req.body;

  if (action === 'analyze') {
    try {
      const { pdfBase64 } = req.body;
      const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
      const response = await client.messages.create({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 500,
        messages: [{
          role: 'user',
          content: [
            { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdfBase64 } },
            { type: 'text', text: '영수증 PDF에서 다음 정보를 추출하여 JSON만 출력하세요 (다른 텍스트 없이):\n{"date":"YYYY/MM/DD","amount":숫자,"merchant":"상호명","product":"상품명"}' }
          ]
        }]
      });
      const text = response.content.map(c => c.text || '').join('');
      const clean = text.replace(/```json?|```/g, '').trim();
      const parsed = JSON.parse(clean);
      return res.status(200).json(parsed);
    } catch (e) {
      return res.status(500).json({ error: '영수증 분석 실패: ' + e.message });
    }
  }

  if (action === 'build') {
    try {
      const { sheet, section, dateVal, amount, merchant, naeyeok } = req.body;
      const buf = Buffer.from(TEMPLATE_B64, 'base64');
      const workbook = XLSX.read(buf, { type: 'buffer' });
      const ws = workbook.Sheets[sheet];
      if (!ws) throw new Error(`"${sheet}" 시트를 찾을 수 없습니다`);

      const [rowStart, rowEnd] = SECTIONS[sheet][section];
      let targetRow = null;
      for (let r = rowStart; r <= rowEnd; r++) {
        const ref = XLSX.utils.encode_cell({ r, c: 1 });
        if (!ws[ref] || ws[ref].v == null || ws[ref].v === '') { targetRow = r; break; }
      }
      if (targetRow === null) throw new Error(`"${section}" 섹션이 가득 찼습니다`);

      const excelDate = dateToExcelSerial(dateVal);
      const payMethod = sheet === '교회체크카드' ? '교회체크카드' : '개인카드';

      ws[XLSX.utils.encode_cell({ r: targetRow, c: 1 })] = { v: excelDate, t: 'n', z: 'YYYY/M/D' };
      ws[XLSX.utils.encode_cell({ r: targetRow, c: 2 })] = { v: Number(amount), t: 'n', z: '#,##0' };
      ws[XLSX.utils.encode_cell({ r: targetRow, c: 3 })] = { v: merchant, t: 's' };
      ws[XLSX.utils.encode_cell({ r: targetRow, c: 4 })] = { v: naeyeok, t: 's' };
      ws[XLSX.utils.encode_cell({ r: targetRow, c: 5 })] = { v: payMethod, t: 's' };
      ws[XLSX.utils.encode_cell({ r: targetRow, c: 7 })] = { v: '신윤호', t: 's' };

      const out = XLSX.write(workbook, { bookType: 'xlsx', type: 'base64' });
      return res.status(200).json({ xlsxBase64: out });
    } catch (e) {
      return res.status(500).json({ error: e.message });
    }
  }

  return res.status(400).json({ error: 'Unknown action' });
}
